11	  customer: { yearsWithMHPCO: number };
12	  steps: QuoteStep[];
13	}
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
17	
18	const BASE_PREMIUM: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	};
23	
24	const quoteStep = (step: QuoteStep): { premium: number } => {
25	  const itemsBase = step.items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
26	  const firstInsuranceSurcharge = itemsBase * FIRST_INSURANCE_SURCHARGE_RATE;
27	  return { premium: itemsBase + firstInsuranceSurcharge + PROCESSING_FEE };
28	};
29	
30	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
31	  const results = scenario.steps.map(quoteStep);
32	  return { results };
33	};
